const prisma = require('../config/prisma');

async function logActivity(payload) {
  return prisma.activityLog.create({
    data: payload,
    include: {
      actor: {
        select: {
          id: true,
          name: true,
          avatar: true,
          role: true
        }
      }
    }
  });
}

module.exports = {
  logActivity
};
